# Gerekli kütüphaneler
from org.apache.nifi.processor.io import StreamCallback
from org.apache.commons.io import IOUtils
from java.time import ZonedDateTime, ZoneId
from java.time.format import DateTimeFormatter
import unicodedata
import re

# Unicode normalizasyonu
def normalize_text(text):
    return unicodedata.normalize('NFKC', text)

# Non-ASCII karakterleri kaldır veya ASCII'ye yakınsayan bir eşdeğerle değiştir
def sanitize_value(value):
    if value:
        value = normalize_text(value)  # Unicode'u normalize et
        value = re.sub(r'[^\x00-\x7F]', '', value)  # Non-ASCII karakterleri kaldır
        value = value.replace("'", "''")  # SQL için tek tırnakları escape et
    return value or "NULL"

# Cluster verilerini ayrıştıran fonksiyon
def parse_cluster_data(cluster_data):
    clusters = []
    current_cluster = {}
    lines = cluster_data.strip().splitlines()
    for line in lines:
        if line.startswith('Datacenter:'):
            if current_cluster:
                clusters.append(current_cluster)
            current_cluster = {'datacenter': line.split(":")[1].strip()}
        elif ':' in line:
            key, value = line.split(":", 1)
            formatted_key = re.sub(r'[^a-zA-Z0-9\s]', '', key.strip()).replace(" ", "_").lower()
            current_cluster[formatted_key] = sanitize_value(value.strip().strip('"'))
    if current_cluster:
        clusters.append(current_cluster)
    return clusters

# SQL insert sorgusunu oluşturan fonksiyon
def generate_insert_sql(cluster_data):
    time = ZonedDateTime.now(ZoneId.of("Europe/Istanbul"))
    collection_time = time.format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss Z"))
    base_sql = "INSERT INTO zabbix_data ("
    column_names = []
    values_list = []
    for cluster in cluster_data:
        columns = []
        values = []
        for key, value in cluster.items():
            columns.append(key)
            values.append("'{}'".format(sanitize_value(value)))
        for col in columns:
            if col not in column_names:
                column_names.append(col)
        values_list.append("({})".format(", ".join(values)))
    sql = "{}{}) VALUES {};".format(base_sql, ", ".join(column_names), ", ".join(values_list))
    return sql

# Akış işlemini yöneten sınıf
class PyStreamCallback(StreamCallback):
    def __init__(self, table_name):
        self.table_name = table_name

    def process(self, inputStream, outputStream):
        # Read the input stream as UTF-8 directly
        try:
            input_text = IOUtils.toString(inputStream, 'utf-8')  # Assumes UTF-8 input
        except Exception as e:
            raise ValueError("Error reading input stream: {}".format(e))

        # Parse the cluster data
        parsed_clusters = parse_cluster_data(input_text)

        # Generate the SQL insert statement
        sql_statement = generate_insert_sql(parsed_clusters)

        # Write the SQL statement to the output stream
        outputStream.write(sql_statement.encode('utf-8'))



# Akış dosyasını işle
flow_file = session.get()
if flow_file is not None:
    table_name = "zabbix_data"
    session.write(flow_file, PyStreamCallback(table_name))
    session.transfer(flow_file, REL_SUCCESS)

