import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.OutputStreamCallback
import java.nio.charset.StandardCharsets

// Akış dosyasını al
def flowFile = session.get()
if (!flowFile) return

// Akış dosyası içeriğini oku
def content = new StringBuilder()
session.read(flowFile, { inputStream ->
    content.append(inputStream.getText("UTF-8"))
} as InputStreamCallback)

def fullText = content.toString()

// Regex ile split et: (?<=;) -> split noktasından önceki ";" karakteri korunur.
def sqlStatements = fullText.split("(?<=;)")

sqlStatements.each { stmt ->
    // Boş satırlara ya da sadece boşluklardan oluşan parçalara dokunmayalım.
    if(stmt?.trim()){
        // Yeni bir akış dosyası oluştur
        def newFlowFile = session.create(flowFile)
        newFlowFile = session.write(newFlowFile, { outputStream ->
            outputStream.write(stmt.getBytes(StandardCharsets.UTF_8))
        } as OutputStreamCallback)
        // Yeni akış dosyasını başarıyla yönlendir
        session.transfer(newFlowFile, REL_SUCCESS)
    }
}

// Orijinal akış dosyasını kaldır
session.remove(flowFile)

# -*- coding: utf-8 -*-

import sys
reload(sys)
sys.setdefaultencoding('utf-8')

from org.apache.nifi.processor.io import StreamCallback
from org.apache.commons.io import IOUtils
from java.time import ZonedDateTime, ZoneId
from java.time.format import DateTimeFormatter
import re

# Cluster verilerini newline'a göre ayırıp dict listesi döner
def parse_cluster_data(cluster_data):
    clusters = []
    current = {}
    for line in cluster_data.strip().splitlines():
        if not line.strip():
            continue
        if line.startswith('Datacenter:'):
            if current:
                clusters.append(current)
            current = {'datacenter': line.split(":", 1)[1].strip()}
        elif ':' in line:
            key, val = line.split(":", 1)
            fk = re.sub(r'[^a-zA-Z0-9\s]', '', key.strip()).replace(" ", "_").lower()
            current[fk] = val.strip().strip('"')
    if current:
        clusters.append(current)
    return clusters

# Dinamik kolon toplayıp INSERT SQL üretir
def generate_insert_sql(cluster_data):
    # 1) Zaman damgası
    now = ZonedDateTime.now(ZoneId.of("Europe/Istanbul"))
    collection_time = now.format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss Z"))

    # 2) Tüm kolon isimlerini tekilleştir
    column_names = []
    for cluster in cluster_data:
        for k in cluster:
            if k not in column_names:
                column_names.append(k)
    # collection_time kolonunu ekle
    if 'collection_time' not in column_names:
        column_names.append('collection_time')

    # 3) Her satır için değerleri hazırla
    values_list = []
    for cluster in cluster_data:
        row_vals = []
        for col in column_names:
            if col == 'collection_time':
                val = collection_time
            else:
                val = cluster.get(col, u"")
            safe = val.replace("'", "''")
            row_vals.append(u"'{}'".format(safe))
        values_list.append(u"({})".format(u", ".join(row_vals)))

    # 4) SQL'i birleştir
    cols = u", ".join(column_names)
    vals = u", ".join(values_list)
    sql = u"INSERT INTO datacenter_metrics ({cols}) VALUES {vals};".format(
        cols=cols, vals=vals
    )
    return sql

class PyStreamCallback(StreamCallback):
    def process(self, inputStream, outputStream):
        text = IOUtils.toString(inputStream, u'utf-8')
        clusters = parse_cluster_data(text)
        sql = generate_insert_sql(clusters)
        outputStream.write(sql.encode('utf-8'))

# ExecuteScript ana bloğu
flow_file = session.get()
if flow_file is not None:
    session.write(flow_file, PyStreamCallback())
    session.transfer(flow_file, REL_SUCCESS)

UPDATE datacenter_metrics
SET DC = UPPER(
    regexp_replace(
        split_part(datacenter, '.', 1),    -- “vc5dc13” kısmını alır
        '^vc[0-9]+',                        -- baştaki “vc” + rakam(lar) kısmını siler
        ''
    )
)
WHERE DC IS NULL;

# -*- coding: utf-8 -*-

import sys
reload(sys)
sys.setdefaultencoding('utf-8')

from org.apache.nifi.processor.io import StreamCallback
from org.apache.commons.io import IOUtils
from java.time import ZonedDateTime, ZoneId
from java.time.format import DateTimeFormatter
import re

def parse_cluster_data(cluster_data):
    clusters = []
    current = {}
    for line in cluster_data.strip().splitlines():
        if line.startswith('Datacenter:'):
            if current:
                clusters.append(current)
            current = {'datacenter': line.split(":", 1)[1].strip()}
        elif ':' in line:
            key, val = line.split(":", 1)
            fk = re.sub(r'[^a-zA-Z0-9\s]', '', key.strip()) \
                  .replace(" ", "_") \
                  .lower()
            current[fk] = val.strip().strip('"')
    if current:
        clusters.append(current)
    return clusters

def generate_insert_sql(cluster_data):
    now = ZonedDateTime.now(ZoneId.of("Europe/Istanbul"))
    collection_time = now.format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss Z"))

    # Tüm kolon isimlerini topla
    column_names = []
    for cluster in cluster_data:
        for key in cluster:
            if key not in column_names:
                column_names.append(key)
    if "collection_time" not in column_names:
        column_names.append("collection_time")

    # Her bir satır için değerleri hazırla
    values_list = []
    for cluster in cluster_data:
        row_vals = []
        for col in column_names:
            if col == "collection_time":
                val = collection_time
            else:
                val = cluster.get(col, u"")
            safe = val.replace("'", "''")
            row_vals.append(u"'{}'".format(safe))
        values_list.append(u"({})".format(u", ".join(row_vals)))

    cols = u", ".join(column_names)
    vals = u", ".join(values_list)
    sql = u"INSERT INTO vm_metrics ({cols}) VALUES {vals};".format(cols=cols, vals=vals)
    return sql

class PyStreamCallback(StreamCallback):
    def process(self, inputStream, outputStream):
        text = IOUtils.toString(inputStream, u'utf-8')
        clusters = parse_cluster_data(text)
        sql = generate_insert_sql(clusters)
        outputStream.write(sql.encode('utf-8'))

flow_file = session.get()
if flow_file is not None:
    session.write(flow_file, PyStreamCallback())
    session.transfer(flow_file, REL_SUCCESS)

